    function parentHexFromRgb(r, g, b) {
      const toHex = n => Math.max(0, Math.min(255, Math.round(Number(n) || 0))).toString(16).padStart(2, "0");
      return ("#" + toHex(r) + toHex(g) + toHex(b)).toLowerCase();
    }

    function parentRgbFromHex(hex) {
      hex = /^#[0-9a-fA-F]{6}$/.test(String(hex || "")) ? String(hex).toLowerCase() : "#000000";
      const n = parseInt(hex.slice(1), 16);
      return {r: (n >> 16) & 255, g: (n >> 8) & 255, b: n & 255};
    }

    function parentParseTextShadowParts(value) {
      value = String(value || "0 1px 2px rgba(0, 0, 0, 0.85)");
      const parts = {x: 0, y: 1, blur: 2, color: "#000000", opacity: 85};
      const rgba = value.match(/rgba?\s*\(\s*([0-9.]+)\s*,\s*([0-9.]+)\s*,\s*([0-9.]+)(?:\s*,\s*([0-9.]+)\s*)?\)/i);
      if (rgba) {
        parts.color = parentHexFromRgb(rgba[1], rgba[2], rgba[3]);
        parts.opacity = parentClampShadowNumber((rgba[4] == null ? 1 : Number(rgba[4])) * 100, 0, 100, 85);
      } else {
        const hex = value.match(/#[0-9a-fA-F]{6}/);
        if (hex) parts.color = String(hex[0]).toLowerCase();
      }
      const numeric = value.replace(/rgba?\s*\([^)]*\)/ig, " ").replace(/#[0-9a-fA-F]{3,6}/g, " ").match(/-?\d+(?:\.\d+)?/g) || [];
      if (numeric.length >= 1) parts.x = parentClampShadowNumber(numeric[0], -12, 12, parts.x, 2);
      if (numeric.length >= 2) parts.y = parentClampShadowNumber(numeric[1], -12, 12, parts.y, 2);
      if (numeric.length >= 3) parts.blur = parentClampShadowNumber(numeric[2], 0, 24, parts.blur, 2);
      return parts;
    }

    function parentBuildTextShadowFromParts(parts) {
      parts = parts || {};
      const x = parentClampShadowNumber(parts.x, -12, 12, 0, 2);
      const y = parentClampShadowNumber(parts.y, -12, 12, 1, 2);
      const blur = parentClampShadowNumber(parts.blur, 0, 24, 2, 2);
      const opacity = parentClampShadowNumber(parts.opacity, 0, 100, 85) / 100;
      const rgb = parentRgbFromHex(parts.color || "#000000");
      return `${parentPxLabel(x)} ${parentPxLabel(y)} ${parentPxLabel(blur)} rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${opacity.toFixed(2).replace(/0+$/, "").replace(/\.$/, "")})`;
    }

