      const currentInputBackgroundColor = /^#[0-9a-fA-F]{6}$/.test(String(data.inputBackgroundColor || "")) ? String(data.inputBackgroundColor).toLowerCase() : "#000000";
      const languageOptions = Array.isArray(data.languageOptions) ? data.languageOptions : [];
      const currentLanguage = String(data.language || "");
